sys_atf_test_step.step:
(function step(assert, $library) {
    // Test IDP Agent Selection CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_agent_selection');
    gr.initialize();
    gr.u_name = 'Test Agent Selection ATF';
    gr.u_agent = 'test-agent';
    var id = gr.insert();
    assert.isTrue(id, 'Agent selection should be created');

    // Read
    gr = new GlideRecord('u_idp_agent_selection');
    gr.get(id);
    assert.equal(gr.u_name, 'Test Agent Selection ATF', 'Agent selection name should match');

    // Update
    gr.u_agent = 'updated-agent';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_agent_selection');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Agent selection should be deleted');
})(step, $library);
